# Classical ML approach: extractive summarization (rule-based/classical)
from heapq import nlargest
from collections import Counter
import re

def extractive_summary(text, n_sentences=2):
    """Pick the n sentences with the highest word frequency scores."""
    sentences = re.split(r'(?<=[.!?]) +', text)
    words = re.findall(r'\w+', text.lower())
    freq = Counter(words)
    # Remove stop words
    stop_words = {'the','a','an','is','in','to','of','and','it','that','this','for'}
    scores = {w: f for w, f in freq.items() if w not in stop_words}
    sentence_scores = {}
    for sent in sentences:
        for word in re.findall(r'\w+', sent.lower()):
            if word in scores:
                sentence_scores[sent] = sentence_scores.get(sent, 0) + scores[word]
    return ' '.join(nlargest(n_sentences, sentence_scores, key=sentence_scores.get))

text = (
    "Artificial intelligence encompasses machine learning and deep learning. "
    "Machine learning models learn patterns from data. "
    "Deep learning uses neural networks with many layers. "
    "Generative AI models like GPT create new text and images. "
    "These technologies are transforming industries worldwide."
)
print("Extractive summary:", extractive_summary(text, n_sentences=2))

# GenAI approach (abstractive) — requires transformers package
try:
    from transformers import pipeline
    summarizer = pipeline("summarization", model="sshleifer/distilbart-cnn-6-6")
    result = summarizer(text, max_length=30, min_length=10, do_sample=False)
    print("Abstractive summary:", result[0]['summary_text'])
except ImportError:
    print("transformers not installed; skipping GenAI summary")
